#include <stdio.h>
#include <string.h> // Required for strlen, strcspn

int main() {
    char str[101]; // Buffer for up to 99 characters + null terminator + potential newline

    // Read a line of text from stdin
    // fgets is safer than scanf for strings, especially with spaces
    if (fgets(str, sizeof(str), stdin) == NULL) {
        return 1; // Error reading input
    }

    // Remove the trailing newline character if it exists
    // strcspn returns the index of the first occurrence of a character from the second string in the first string
    str[strcspn(str, "\n")] = '\0';

    int length = strlen(str);

    // Reverse the string in-place
    for (int i = 0, j = length - 1; i < j; i++, j--) {
        char temp = str[i];
        str[i] = str[j];
        str[j] = temp;
    }

    // Print the reversed string followed by a newline
    printf("%s\n", str);

    return 0;
}
